import {UseApplicationParams,} from "./type";
import {AppSystemCommProtocol} from "./ascp";
import {MainScenariosEventMap} from "./event/acp";

export interface MainAcpScenariosListenerMap {
    onUseApplication(params: UseApplicationParams): void
    onLogout(): void
}

export interface MainAcpMethodMap {

}

class MainAcp extends AppSystemCommProtocol implements MainAcpMethodMap {
    constructor(acpScenarioHandlerMapFromProps: MainAcpScenariosListenerMap) {
        const eventHandlerMap = new Map() as Map<symbol | string, Function>
        (Object.keys(acpScenarioHandlerMapFromProps) as (keyof typeof acpScenarioHandlerMapFromProps)[]).forEach((handlerName) => {
            eventHandlerMap.set(MainScenariosEventMap[handlerName], acpScenarioHandlerMapFromProps[handlerName])
        })
        super('work-station', eventHandlerMap)
    }
}


/**
 * 启用 spotter 应用通信协议（ spotter application communication protocol ）
 * @param handlerMap
 */
export function startMainAcp(handlerMap: MainAcpScenariosListenerMap): { acp: MainAcp } {
    const acp = new MainAcp(handlerMap)
    return {
        acp,
    }
}
